from flask import Flask, request
import logging
from logging.handlers import RotatingFileHandler
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

users = {}

@app.route('/register', methods=['POST'])
def register():
    username = request.json.get('username')
    password = request.json.get('password')
    email = request.json.get('email')
    if username in users:
        return "User already exists", 400
    else:
        users[username] = {
            'password': generate_password_hash(password),
            'email': email
        }
        return "User created successfully", 201

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    user = users.get(username)
    if user and check_password_hash(user['password'], password):
        app.logger.info('User %s logged in successfully with email %s from IP %s with User Agent %s', username, user['email'], request.remote_addr, request.user_agent)
        return "Logged in successfully", 200
    else:
        app.logger.warning('Failed login attempt by user %s with email %s from IP %s with User Agent %s', username, user['email'] if user else 'N/A', request.remote_addr, request.user_agent)
        return "Invalid username or password", 401

if __name__ == '__main__':
    handler = RotatingFileHandler('application.log', maxBytes=10000, backupCount=3)
    logger = logging.getLogger('werkzeug')
    logger.setLevel(logging.INFO)
    logger.addHandler(handler)
    app.logger.addHandler(handler)
    app.run(debug=True)